// src/components/ExampleJournal.tsx
// Static example journal section for the landing page.
// Images are embedded as base64 to avoid external dependencies.

import styles from "./ExampleJournal.module.css";

const BENCH = "data:image/jpeg;base64,";
const SPRUCE = "data:image/jpeg;base64,";
const PIGEON = "data:image/jpeg;base64,";

function PhotoPrint({ src, tilt, float: f }: { src: string; tilt: number; float: "left" | "right" }) {
  const margin = f === "right"
    ? { float: "right" as const, margin: "0 0 20px 28px" }
    : { float: "left" as const, margin: "0 28px 20px 0" };
  return (
    <div style={{ ...margin, display: "inline-block" }}>
      <div style={{
        background: "white",
        padding: "7px 7px 26px 7px",
        boxShadow: "0 2px 4px rgba(0,0,0,0.18), 0 6px 16px rgba(0,0,0,0.12)",
        transform: `rotate(${tilt}deg)`,
        display: "inline-block",
      }}>
        <img src={src} alt="field sketch" style={{ display: "block", width: 160, height: 120, objectFit: "cover" }} />
      </div>
    </div>
  );
}

const ENTRIES = [
  {
    n: "01",
    stamp: "September 15, 2025 · 2:17 pm",
    image: BENCH,
    tilt: -2.1,
    float: "right" as const,
    body: [
      "First visit. The bench faces east, which I hadn't noticed before — the morning light would be entirely different here. There's a spruce directly behind it, close enough to reach out and touch the bark. The stone is cold and slightly damp even though it hasn't rained.",
      "Two pigeons. One has a gray band on its left leg.",
    ],
  },
  {
    n: "02",
    stamp: "September 19, 2025 · 11:43 am",
    image: PIGEON,
    tilt: 1.6,
    float: "left" as const,
    body: [
      "The banded pigeon is here again. I am beginning to think of this as its bench, not mine. The lichen on the north face of the stone has a pattern I can only see now that I know to look for it — pale green, roughly circular, about the size of a palm.",
      "Someone left a single glove on the armrest. Right hand, dark green wool.",
    ],
  },
  {
    n: "03",
    stamp: "October 3, 2025 · 4:05 pm",
    image: SPRUCE,
    tilt: -1.4,
    float: "right" as const,
    body: [
      "The leaves on the maple to the left are turning. Not all at once — the ones at the top went first, then the outer branches, now it's moving inward. I looked this up: it's called acropetal senescence. The tree is systematically withdrawing chlorophyll.",
      "The glove is gone. The bench remembers nothing.",
    ],
  },
];

export default function ExampleJournal() {
  return (
    <section className={styles.section} id="example-journal">
      <div className={styles.inner}>
        <p className={`${styles.label} mono`}>example field journal</p>
        <h2 className={styles.heading}>The stone bench behind Collis</h2>
        <p className={styles.sub}>
          A sample journal — how observations accumulate over a term from a single campus spot.
        </p>

        {ENTRIES.map((entry) => (
          <div key={entry.n} className={styles.entry} style={{ overflow: "hidden" }}>
            <span className={`${styles.entryNum} mono tiny`}>{entry.n}</span>
            <span className={`${styles.stamp} mono tiny muted`}>{entry.stamp}</span>
            <PhotoPrint src={entry.image} tilt={entry.tilt} float={entry.float} />
            <div className={styles.prose}>
              {entry.body.map((p, i) => <p key={i}>{p}</p>)}
            </div>
          </div>
        ))}
      </div>
    </section>
  );
}
